SELECT EXISTS (
    SELECT 1
    FROM resumes r
    JOIN personal_profiles pp ON pp.id = r.personal_profile_id
    WHERE r.id = #{resumeId}
      AND pp.user_id = #{receiverUserId}
      AND r.deleted_at IS NULL
      AND r.visibility IN ('PUBLIC', 'COMPANY_ONLY')
)

